import math
doc = Rhino.RhinoDoc.ActiveDoc
xform = Rhino.Geometry.Transform.Rotation(math.pi / 4, Rhino.Geometry.Vector3d.ZAxis, Rhino.Geometry.Point3d.Origin)
rotated = 0
for obj in doc.Objects.GetSelectedObjects(False, False):
    if doc.Objects.Transform(obj.Id, xform, True) != System.Guid.Empty:
        rotated += 1
doc.Views.Redraw()
return {"rotated": rotated, "degrees": 45, "axis": "Z"}
